when.content:
function addTask() {
    const title = prompt('Enter task title:');
    if (title && title.trim() !== '') {
        const task = {
            title: title.trim(),
            completed: false,
            date: new Date().toLocaleString()
        };
        tasks.unshift(task);
        renderTaskList();
    }
}

function completeTask(index) {
    tasks[index].completed = !tasks[index].completed;
    renderTaskList();
}

